/**
 * User helper utilities
 */

/**
 * Extract user ID from API Gateway event with Cognito authorizer
 * @param {object} event - API Gateway event
 * @returns {string} user ID (Cognito sub)
 */
function getUserIdFromEvent(event) {
    // For API Gateway with Cognito Authorizer
    if (event.requestContext && event.requestContext.authorizer && event.requestContext.authorizer.claims) {
        return event.requestContext.authorizer.claims.sub;
    }
    // For Cognito trigger events
    if (event.userName) {
        return event.userName;
    }
    if (event.request && event.request.userAttributes && event.request.userAttributes.sub) {
        return event.request.userAttributes.sub;
    }
    throw new Error('Unable to extract user ID from event');
}

/**
 * Extract user email from API Gateway event with Cognito authorizer
 * @param {object} event - API Gateway event
 * @returns {string} user email
 */
function getUserEmailFromEvent(event) {
    if (event.requestContext && event.requestContext.authorizer && event.requestContext.authorizer.claims) {
        return event.requestContext.authorizer.claims.email;
    }
    if (event.request && event.request.userAttributes && event.request.userAttributes.email) {
        return event.request.userAttributes.email;
    }
    return null;
}

module.exports = {
    getUserIdFromEvent,
    getUserEmailFromEvent
};
